import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a cash back offer on a car?", a: "A cash back offer is a rebate that reduces the purchase price or loan amount, often offered by a dealer or manufacturer." },
  { q: "What is 0% financing?", a: "0% financing is a loan promotion where the borrower pays no interest during the loan term if all terms are met." },
  { q: "How do you calculate which is better - cash back or low interest?", a: "Compare the total loan cost under the rebate with standard financing against the total cost under the low-rate financing offer." },
  { q: "Can you negotiate both cash back and low interest?", a: "Sometimes offers cannot be combined, but dealers may have flexibility on price, fees, or trade-in value." },
  { q: "Does financing affect your credit score?", a: "Applying for and using financing can affect credit through inquiries, account age, balances, and payment history." },
];
const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function payment(principal: number, apr: number, months: number) { const r = apr / 100 / 12; return r === 0 ? principal / months : principal * r / (1 - Math.pow(1 + r, -months)); }
function scenario(price: number, down: number, months: number, apr: number, rebate = 0) { const financed = Math.max(0, price - down - rebate); const monthly = payment(financed, apr, months); const total = monthly * months + down; return { financed, monthly, interest: monthly * months - financed, total }; }
type DealRow = [string, string, ReturnType<typeof scenario>];

export default function CashBackVsLowInterestCalculator() {
  useCurrencyVersion();
  const [price, setPrice] = useState(30000), [down, setDown] = useState(3000), [term, setTerm] = useState(60), [standardRate, setStandardRate] = useState(7), [cashBack, setCashBack] = useState(2000), [lowRate, setLowRate] = useState(1.9);
  const result = useMemo(() => { const cash = scenario(price, down, term, standardRate, cashBack); const low = scenario(price, down, term, lowRate, 0); return { cash, low, winner: cash.total < low.total ? "Cash back" : "Low interest", savings: Math.abs(cash.total - low.total) }; }, [price, down, term, standardRate, cashBack, lowRate]);
  const examples: DealRow[] = [
    ["Cash Back", "$1,000", scenario(30000, 3000, 60, 7, 1000)],
    ["Cash Back", "$2,000", scenario(30000, 3000, 60, 7, 2000)],
    ["Low Interest", "3.9%", scenario(30000, 3000, 60, 3.9, 0)],
    ["Low Interest", "1.9%", scenario(30000, 3000, 60, 1.9, 0)],
    ["0% Financing", "0%", scenario(30000, 3000, 60, 0, 0)],
  ];
  const best = Math.min(...examples.map((e) => e[2].total));
  return (
    <>
      <SEOHead title="Free Cash Back vs Low Interest Calculator Online - Find Which Deal Saves More Money | CalcHive" description="Free online cash back vs low interest calculator. Compare cash back offers against low interest rate financing to find which saves you more money on any purchase instantly. 100% free, no signup required." canonical="/cash-back-vs-low-interest-calculator" keywords="free cash back vs low interest calculator, cash back or financing calculator free, compare auto loan deals free online, cash back vs 0% financing calculator free, car deal comparison calculator free" category="Financial Calculators" breadcrumbName="Free Cash Back or Low Interest Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Cash Back or Low Interest Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Compare rebate financing against low interest financing to see which option saves more.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">{[["Purchase price", price, setPrice], ["Down payment", down, setDown], ["Loan term months", term, setTerm], ["Standard rate (%)", standardRate, setStandardRate], ["Cash back offer", cashBack, setCashBack], ["Low interest rate (%)", lowRate, setLowRate]].map(([label, value, setter]) => <div key={String(label)}><label className="text-sm font-semibold text-foreground block mb-2">{String(label)}</label><input type="number" value={Number(value)} onChange={(e) => (setter as (v: number) => void)(Number(e.target.value))} className={inputClass} /></div>)}</div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Better Deal</p><p className="text-5xl sm:text-6xl font-black text-white">{result.winner}</p><p className="text-white/80 mt-2">Saves {money(result.savings)}</p></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Compare Cash Back vs Low Interest Deals for Free</h2><p className="text-muted-foreground leading-relaxed">This car deal comparison calculator compares total cost after down payment, rebate, monthly payments, and interest.</p>
          <h2 className="text-2xl font-bold text-foreground">When Cash Back Beats Low Interest and When It Doesn't</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Cash Back vs Low Interest - $30,000 Car Example</caption><thead className="bg-muted/60"><tr>{["Scenario", "Cash Back Amount or Rate", "Financed Amount", "Monthly Payment", "Total Interest", "Total Cost", "Savings"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{examples.map(([name, offer, data]) => <tr key={`${name}-${offer}`}><td className="py-2.5 px-3 font-semibold">{String(name)}</td><td className="py-2.5 px-3">{String(offer)}</td><td className="py-2.5 px-3">{money(data.financed)}</td><td className="py-2.5 px-3">{money(data.monthly)}</td><td className="py-2.5 px-3">{money(data.interest)}</td><td className="py-2.5 px-3">{money(data.total)}</td><td className="py-2.5 px-3">{money(data.total - best)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Car Financing Deal Comparison Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Cash back usually helps most when the rebate is large, while low-rate financing helps most over longer terms or larger loan balances.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/cash-back-vs-low-interest-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


